import type { ThemeTokenSource } from './types';

/**
 * The complete set of Tailwind v4 `@theme` namespaces whose name spans more than
 * one dash-segment. Every other namespace (`color`, `radius`, `font`, …) is a
 * single segment, so the namespace is normally everything before the first dash
 * — but these would then misfile under their first segment (`--font-weight-bold`
 * under `font`, `--text-shadow-lg` under `text`), polluting a surfaced namespace.
 */
const MULTI_SEGMENT_NAMESPACES = [
  'font-weight',
  'text-shadow',
  'inset-shadow',
  'drop-shadow',
];

/** Split a `--ns-suffix` custom property into its `@theme` namespace and suffix. */
function splitNamespace(name: string): { ns: string; suffix: string } {
  const bare = name.slice(2);
  const ns =
    MULTI_SEGMENT_NAMESPACES.find((m) => bare.startsWith(`${m}-`)) ??
    bare.split('-', 1)[0];

  return { ns, suffix: bare.slice(ns.length + 1) };
}

/**
 * Parse a Tailwind v4 stylesheet into the app's `@theme` token source: each
 * token split into its `suffix` and raw value `expr`, grouped by namespace.
 * Values are captured verbatim — `var()`/`calc()` are resolved later, in the
 * browser. Pure, dependency-free, and never throws.
 *
 * @param css - Contents of the entry stylesheet (the file with the `@theme` block).
 * @returns The token source keyed by namespace, or `undefined` when the CSS has
 *   no `@theme` block or yields no named tokens.
 *
 * @example
 * parseThemeTokens('@theme { --color-primary: hsl(var(--primary)); }');
 * // => { color: [{ suffix: 'primary', expr: 'hsl(var(--primary))' }] }
 */
export function parseThemeTokens(css: string): ThemeTokenSource | undefined {
  try {
    const stripped = css.replace(/\/\*[\s\S]*?\*\//g, '');

    // The final declaration in a block may be terminated by `}` (i.e. end of
    // the sliced body) rather than `;`, which CSS permits.
    const declRegex = /(--[\w-]+)\s*:\s*([^;]+?)\s*(?:;|$)/g;
    const source: ThemeTokenSource = {};
    let found = false;

    let searchFrom = 0;
    while (true) {
      const keywordIndex = stripped.indexOf('@theme', searchFrom);
      if (keywordIndex === -1) {
        break;
      }

      const openBrace = stripped.indexOf('{', keywordIndex);
      if (openBrace === -1) {
        break;
      }

      // Brace-match by depth counting to find the block's closing '}'.
      let depth = 1;
      let cursor = openBrace + 1;
      while (cursor < stripped.length && depth > 0) {
        const char = stripped[cursor];
        if (char === '{') {
          depth += 1;
        } else if (char === '}') {
          depth -= 1;
        }

        cursor += 1;
      }

      // An unterminated block (no matching '}') is malformed: the end-of-body
      // terminator below would otherwise capture a truncated value. Skip it.
      if (depth > 0) {
        break;
      }

      const body = stripped.slice(openBrace + 1, cursor - 1);
      searchFrom = cursor;

      for (const match of body.matchAll(declRegex)) {
        const name = match[1];
        const expr = match[2].trim().replace(/\s+/g, ' ');

        const { ns, suffix } = splitNamespace(name);

        // Skip `--<token>--<property>` companions (e.g. `--text-sm--line-height`) — never standalone tokens.
        if (suffix.includes('--')) {
          continue;
        }

        if (suffix !== '') {
          const entries = (source[ns] ??= []);
          const existing = entries.findIndex((e) => e.suffix === suffix);
          if (existing === -1) {
            entries.push({ suffix, expr });
          } else {
            // Last declaration wins.
            entries[existing] = { suffix, expr };
          }

          found = true;
        }
      }
    }

    if (!found) {
      return undefined;
    }

    return source;
  } catch {
    return undefined;
  }
}
